/// LISTING-LOOP
fn p_listing_loop(state: &mut ProgramState) {
    match new_version_read(state) {
        Ok(()) => {
            // record read successfully
        }
        Err(FileStatus::AtEnd) => {
            p_end_job(state); return;
            state.activities_listing.active_image = FixedString::copy_from(&state.new_record);
            {
            let mut _bytes = vec![b' '; 82];
            { let _src = state.activities_listing.disposition.as_bytes(); let _end = (0+2).min(_bytes.len()); let _cl = _src.len().min(_end-0); _bytes[0..0+_cl].copy_from_slice(&_src[.._cl]); }
            { let _src = state.activities_listing.active_image.as_bytes(); let _end = (2+80).min(_bytes.len()); let _cl = _src.len().min(_end-2); _bytes[2..2+_cl].copy_from_slice(&_src[.._cl]); }
            let _len = _bytes.len();
            }
            comment_line_write(state);
            state.line_count += 1 as u32;
            if state.line_count == 56 {
                p_top_of_page_routine(state);
                p_listing_loop(state); return;
            }
        }
        Err(_) => {
            // other file error
        }
    }
}

/// END-JOB
fn p_end_job(state: &mut ProgramState) {
    state.message_log.message_text = "PROGRAM TERMINATION".into();
    {
    let mut _bytes = vec![b' '; 82];
    { let _src = state.message_log.message_text.as_bytes(); let _end = (2+80).min(_bytes.len()); let _cl = _src.len().min(_end-2); _bytes[2..2+_cl].copy_from_slice(&_src[.._cl]); }
    let _len = _bytes.len();
    }
    comment_line_write(state);
    old_version_close(state);
    new_version_close(state);
    modification_close(state);
    commentary_close(state);
    { let _ = state._fh_old_version.close();
        let _ = state._fh_new_version.close();
        let _ = state._fh_modification.close();
        let _ = state._fh_commentary.close();
        std::process::exit(0); }
}

