/// OPEN EXTEND MODIFICATION
fn modification_open_extend(state: &mut ProgramState) {
    let path = std::env::var("MODIFICATION").unwrap_or("modification.dat".to_string());
    match CobolFile::open_extend(&path) {
        Ok(handle) => { state._fh_modification = handle; state._fs_modification = FileStatus::Success; }
        Err(_) => { state._fs_modification = FileStatus::Error("35".to_string()); }
    }
}

/// OPEN INPUT COMMENTARY
fn commentary_open_input(state: &mut ProgramState) {
    let path = std::env::var("COMMENTARY").unwrap_or("commentary.dat".to_string());
    match CobolFile::open_input(&path) {
        Ok(handle) => { state._fh_commentary = handle; state._fs_commentary = FileStatus::Success; }
        Err(_) => { state._fs_commentary = FileStatus::Error("35".to_string()); }
    }
}

/// OPEN OUTPUT COMMENTARY
fn commentary_open_output(state: &mut ProgramState) {
    let path = std::env::var("COMMENTARY").unwrap_or("commentary.dat".to_string());
    match CobolFile::open_output(&path) {
        Ok(handle) => { state._fh_commentary = handle; state._fs_commentary = FileStatus::Success; }
        Err(_) => { state._fs_commentary = FileStatus::Error("35".to_string()); }
    }
}

/// READ COMMENTARY
fn commentary_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_commentary.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(82);
            state._fs_commentary = FileStatus::Success;
        }
        Err(FileStatus::AtEnd) => {
            state._fs_commentary = FileStatus::AtEnd;
        }
        Err(e) => {
            state._fs_commentary = e.clone();
        }
    }
    Ok(())
}

/// WRITE to COMMENTARY
fn commentary_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 82];
    match state._fh_commentary.write_record(&_buf) {
        Ok(()) => state._fs_commentary = FileStatus::Success,
        Err(e) => state._fs_commentary = e,
    }
}

/// CLOSE COMMENTARY
fn commentary_close(state: &mut ProgramState) {
    match state._fh_commentary.close() {
        Ok(()) => state._fs_commentary = FileStatus::Success,
        Err(e) => state._fs_commentary = e,
    }
}

