/// WRITE COMMENT-LINE
fn comment_line_write(state: &mut ProgramState) {
    // Write COMMENT-LINE via commentary_write (byte buffer)
    commentary_write(state);
}

/// WRITE NEW-RECORD
fn new_record_write(state: &mut ProgramState) {
    // Write NEW-RECORD via new_version_write (byte buffer)
    new_version_write(state);
}

fn main() {
    let mut state = ProgramState::default();
    p_start_section(&mut state);
}

